class PostVoting{constructor(){this.upvoteButton=document.getElementById("upvote-button"),this.downvoteButton=document.getElementById("downvote-button"),this.scoreCount=document.getElementById("post-score-count"),this.postID=document.getElementById("content-container").dataset.postId,this.upvoteButton.onclick=()=>{this.addUpvote()},this.downvoteButton.onclick=()=>{this.addDownvote()}}addUpvote(){if(this.upvoteButton.classList.contains("disabled"))return;this.upvoteButton.classList.add("disabled"),this.downvoteButton.classList.add("disabled");let t=new Headers;t.append("Content-Type","application/json");let o={method:"POST",headers:t,body:JSON.stringify({post_id:this.postID})};fetch("/api/posts/upvote",o).then(t=>t.json()).then(t=>{this.updateButtons(t)}).catch(t=>console.error(t))}addDownvote(){if(this.downvoteButton.classList.contains("disabled"))return;this.upvoteButton.classList.add("disabled"),this.downvoteButton.classList.add("disabled");let t=new Headers;t.append("Content-Type","application/json");let o={method:"POST",headers:t,body:JSON.stringify({post_id:this.postID})};fetch("/api/posts/downvote",o).then(t=>t.json()).then(t=>{this.updateButtons(t)}).catch(t=>console.error(t))}updateButtons(t){this.scoreCount.innerText=t.score,t.score>0?this.scoreCount.className="positive":t.score<0?this.scoreCount.className="negative":this.scoreCount.className="neutral",t.has_downvoted?(this.downvoteButton.classList.add("voted"),this.upvoteButton.classList.remove("voted")):t.has_upvoted?(this.upvoteButton.classList.add("voted"),this.downvoteButton.classList.remove("voted")):t.has_downvoted||t.has_upvoted||(this.upvoteButton.classList.remove("voted"),this.downvoteButton.classList.remove("voted")),this.upvoteButton.classList.remove("disabled"),this.downvoteButton.classList.remove("disabled")}}export{PostVoting};